 85→const DIFFICULTY_CLASS: Record<string, string> = {
 86→  Beginner: "build-card-difficulty--beginner",
 87→  Intermediate: "build-card-difficulty--intermediate",
 88→  Advanced: "build-card-difficulty--advanced",
 89→};
 90→
 91→interface BuildCardProps {
 92→  build: BuildOrder;
 93→  elapsed: number;
 94→  running: boolean;
 95→  borderImageUrl: string;
 96→}
 97→
 98→const VALID_RACES = new Set<string>(["Human", "Orc", "NightElf", "Undead"]);
 99→
100→function BuildCard({ build, elapsed, running, borderImageUrl }: BuildCardProps) {
101→  const tableRef = useRef<HTMLDivElement>(null);
102→  const [scrollPct, setScrollPct] = useState(0);
103→  const scrollingFromBar = useRef(false);
104→  const supplyIconUrl = useSupplyIcon();
105→  const buildRace = VALID_RACES.has(build.race)
106→    ? (build.race as Race)
107→    : null;
108→
109→  const activeStepIndex = (() => {
110→    let idx = -1;
111→    for (let i = 0; i < build.steps.length; i++) {
112→      if (parseStepTime(build.steps[i].time) <= elapsed) idx = i;
113→    }
114→    return idx;
115→  })();
116→
117→  // Sync native scroll → scrollbar percentage
118→  useEffect(() => {
119→    const el = tableRef.current;
120→    if (!el) return;
121→    const handler = () => {
122→      if (scrollingFromBar.current) return;
123→      const maxScroll = el.scrollHeight - el.clientHeight;
124→      if (maxScroll <= 0) {
125→        setScrollPct(0);
126→        return;
127→      }
128→      setScrollPct((el.scrollTop / maxScroll) * 100);
129→    };
130→    el.addEventListener("scroll", handler, { passive: true });
131→    return () => el.removeEventListener("scroll", handler);
132→  }, []);
133→
134→  // Scrollbar → native scroll
135→  const handleScrollbarChange = useCallback((pct: number) => {
136→    setScrollPct(pct);
137→    const el = tableRef.current;
138→    if (!el) return;
139→    const maxScroll = el.scrollHeight - el.clientHeight;
140→    if (maxScroll <= 0) return;
141→    scrollingFromBar.current = true;
142→    el.scrollTop = (pct / 100) * maxScroll;
143→    requestAnimationFrame(() => {
144→      scrollingFromBar.current = false;
145→    });
146→  }, []);
147→
148→  // Auto-scroll the active step into view
149→  useEffect(() => {
150→    if (activeStepIndex < 0 || !tableRef.current) return;
151→    const row = tableRef.current.querySelectorAll(".build-step-row")[
152→      activeStepIndex
153→    ] as HTMLElement | undefined;
154→    if (row) {
155→      row.scrollIntoView({ block: "nearest", behavior: "smooth" });
156→    }
157→  }, [activeStepIndex]);
158→
159→  // border-image applied only to the active row; all rows already reserve
160→  // 6px transparent border space in CSS so nothing shifts.
161→  const activeBorderStyle: React.CSSProperties | undefined = borderImageUrl
162→    ? {
163→        borderImageSource: `url("${borderImageUrl}")`,
164→        borderImageSlice: 64,
165→        borderImageWidth: 1,
166→        borderImageRepeat: "round",
167→      }
168→    : undefined;
169→
170→  return (
171→    <div className="build-card">
