 64→  if (inBounds(startX, startY) && alphaAt(startX, startY) === 0) return startY * width + startX;
 65→  const maxRadius = Math.max(width, height);
 66→  for (let r = 1; r < maxRadius; r++) {
 67→    for (let dy = -r; dy <= r; dy++) {
 68→      const y = startY + dy;
