 71→  const preferencesByRace: Record<Race, readonly string[]> = {
 72→    Human: ['stand work', 'stand lumber', 'stand ready', 'stand gold', 'stand - 3', 'stand -3', 'stand 2', 'stand - 2', 'stand'],
